  import sailpoint.tools.Util;
  import java.io.File;
	import java.io.FileNotFoundException;
	import java.util.Scanner;
  import sailpoint.object.Custom;
  
  import sailpoint.tools.Message;
  
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Rule-OIM-Data-Creation-AMITA");
  
  /**
   * Method to read the full file and collect the data
	 * @param filePath
	 * @return
	 */
  	public Map readFullDataFile(String filePath) {
		logger.debug("Entering method readFullDataFile ");
		int lineCount = 0;
		String headerString = null;
		int headerLength = 0;
    Map outputMap = new HashMap();
    Map allUsersMap = new HashMap();
		String[] headerSplit = null;
		Map identityMap = null;
		Scanner sc = null;
		try {
      if (Util.isNotNullOrEmpty(filePath)){
				File file = new File(filePath);
				if ((!file.exists()) || (file.isDirectory())) {
					logger.error("File doesnt exist");
				
					 taskResult.addMessage(new Message(Message.Type.Error, "The file " + file + " does not exist.", null));
					 taskResult.setCompletionStatus(sailpoint.object.TaskResult.CompletionStatus.Error);
           
				} else {
					try {
						sc = new Scanner(file);
					} catch (FileNotFoundException e1) {
						 logger.error("FileNotFoundException : "+e1.getMessage());
					}
					while (sc.hasNextLine()) {
						String line = sc.nextLine();
						if(Util.isNotNullOrEmpty(line) && line.endsWith("|")){
							line = line+" ";
						}
						if (lineCount == 0) {
							headerString = line;
							lineCount++;
							if (Util.isNotNullOrEmpty(headerString) && headerString.contains("|")) {
								 headerSplit = headerString.split("\\|");
								if (headerSplit != null) {
									headerLength = headerSplit.length;
								}
							}
							continue;
						}
						if (Util.isNotNullOrEmpty(line) && line.contains("|")) {
							identityMap = new HashMap();
							String[] eachLineSplit = line.split("\\|");
							if (eachLineSplit != null && eachLineSplit.length == headerLength) {
								for(int headerStart = 0; headerStart < headerLength; headerStart++){
										identityMap.put(headerSplit[headerStart], eachLineSplit[headerStart]);
								}
							}
						}
            
            // if Primary Job Indicator is Y then only add to allUserMap
            if(!Util.isEmpty(identityMap) && Util.nullSafeCaseInsensitiveEq("Y",identityMap.get("Primary Job Indicator"))){
              allUsersMap.put(identityMap.get("Person ID"),identityMap);
            }
           
						lineCount++;
					}
				}
			}
		}catch(Exception ex){
			logger.error("Exception readInputFile :: "+ex.getMessage());
			taskResult.addMessage(new Message(Message.Type.Error, "Exception : "+ex.getMessage(), null));
		} finally {
			if(sc != null)
			sc.close();
		}
    outputMap.put("Full Data", allUsersMap);
    logger.debug("Exiting method readFullDataFile ");
		return outputMap;
	}


 /**
   * Method to read the input file
	 * @param filePath
	 * @return
	 */
	public List readInputFile(String filePath, String customObjectName) {
		logger.debug("Entering method readInputFile ");
		int lineCount = 0;
		String headerString = null;
		int headerLength = 0;
		List allUsersList = new ArrayList();
		String[] headerSplit = null;
		Map identityMap = null;
		Scanner sc = null;
		try {
      if (Util.isNotNullOrEmpty(filePath) && Util.isNotNullOrEmpty(customObjectName)){
				File file = new File(filePath);
				if ((!file.exists()) || (file.isDirectory())) {
					logger.error("File doesnt exist");
					
					 taskResult.addMessage(new Message(Message.Type.Error, "The file " + file + " does not exist.", null));
					 taskResult.setCompletionStatus(sailpoint.object.TaskResult.CompletionStatus.Error);
          
				} else {
					try {
						sc = new Scanner(file);
					} catch (FileNotFoundException e1) {
						 logger.error("FileNotFoundException : "+e1.getMessage());
					}
					while (sc.hasNextLine()) {
						String line = sc.nextLine();
						if(Util.isNotNullOrEmpty(line) && line.endsWith("|")){
							line = line+" ";
						}
						if (lineCount == 0) {
							headerString = line;
              Custom custom = context.getObjectByName(Custom.class, customObjectName);
              if(custom != null){
                if(Util.isNotNullOrEmpty(headerString) && headerString.contains("Oprid")){
                  headerString = headerString.replace("Oprid","OprId");
                }
                custom.put("Delta Header",headerString);
                context.saveObject(custom);
                context.commitTransaction();
                //comment decache //context.decache(custom);
              }
							lineCount++;
							if (Util.isNotNullOrEmpty(headerString) && headerString.contains("|")) {
								 headerSplit = headerString.split("\\|");
								if (headerSplit != null) {
									headerLength = headerSplit.length;
								}
							}
							continue;
							
						}
						if (Util.isNotNullOrEmpty(line) && line.contains("|")) {
							identityMap = new HashMap();
							String[] eachLineSplit = line.split("\\|");
							if (eachLineSplit != null && eachLineSplit.length == headerLength) {
								for(int headerStart = 0; headerStart < headerLength; headerStart++){
										identityMap.put(headerSplit[headerStart], eachLineSplit[headerStart]);
								}
							}
						}
						allUsersList.add(identityMap);
						lineCount++;
					}
				}
			}
		}catch(Exception ex){
			logger.error("Exception readInputFile :: "+ex.getMessage());
			taskResult.addMessage(new Message(Message.Type.Error, "Exception : "+ex.getMessage(), null));
		} finally {
			if(sc != null)
			sc.close();
		}
    logger.debug("Exiting method readInputFile ");
    if(!Util.isEmpty(allUsersList)){
      taskResult.setAttribute("deltaRecordsCount",allUsersList.size()); 
    }else{
          taskResult.setAttribute("deltaRecordsCount",0); 
    }
		return allUsersList;
	}
  

  
  if((void != config) && (null != config) && (config instanceof Map)){
	  String fileLocation = config.get("filePath");
    String customObjectName = "Ascension-Custom-OIM-Data-Ascension";
    
	  if(Util.isNotNullOrEmpty(fileLocation) && Util.isNotNullOrEmpty(customObjectName)){
      
       String headerString = null;
       String outputFilePath = null;
       StringBuffer data = new StringBuffer();
       Map headersMap= new HashMap();
       String fullFeedFilePath = null;
       List identitiesFromCustom = new ArrayList();
       List expectionIds = new ArrayList();
       
      
      Custom custom = context.getObjectByName(Custom.class, customObjectName);
      List<Map> updatedDataList = new ArrayList();
      List allHeadersList = new ArrayList();
      
      //Read all the data from the file and add each line as a Map ; All lines ared added as a List
      List<Map> allUsersList = readInputFile(fileLocation,customObjectName);
      
      if(!Util.isEmpty(allUsersList) && custom !=  null){
      	outputFilePath  = custom.get("Delta Output Path");
        identitiesFromCustom = custom.get("Identities Changed");
        if(!Util.isEmpty(identitiesFromCustom)){
			Util.removeDuplicates(identitiesFromCustom);
          taskResult.setAttribute("identitiesFromEventsCount",identitiesFromCustom.size()); 
        }else{
          taskResult.setAttribute("identitiesFromEventsCount",0); 
        }
        headerString = custom.get("Delta Header");
        expectionIds = custom.get("Exception Identities");
        if(!Util.isEmpty(expectionIds)){
			Util.removeDuplicates(expectionIds);
          taskResult.setAttribute("expectionIdsCount",expectionIds.size()); 
        }else{
          taskResult.setAttribute("expectionIdsCount",0); 
        }
        
        fullFeedFilePath = custom.get("Full Feed File Path");
        
       // HeaderString is added from file to the Custom object - check if email and OprId are presnt in the Header. If not, add them at the end
        if(Util.isNotNullOrEmpty(headerString) && ! headerString.contains("Email Address")){
        	headerString = headerString+"|Email Address";
        }
        if(Util.isNotNullOrEmpty(headerString) && headerString.contains("Oprid")){
          headerString = headerString.replace("Oprid","OprId");
        }else if(Util.isNotNullOrEmpty(headerString) && ! headerString.contains("OprId")){
          headerString = headerString+"|OprId";
        }
        custom.put("Delta Header",headerString);
        context.saveObject(custom);
        context.commitTransaction();
        //comment decache //context.decache(custom);
       }
      
      
      //Before begin add expection list to identities from event to process
      if(!Util.isEmpty(expectionIds)){
        if(identitiesFromCustom != null && !Util.isEmpty(identitiesFromCustom)){
      	  identitiesFromCustom.addAll(expectionIds);
        }else{
          identitiesFromCustom = new ArrayList();
          identitiesFromCustom.addAll(expectionIds);
        }
		Util.removeDuplicates(identitiesFromCustom);
        Custom custom = context.getObjectByName(Custom.class, customObjectName);
        if(custom != null){
          expectionIds = new ArrayList();
          custom.put("Exception Identities", new ArrayList());
          custom.put("Identities Changed", identitiesFromCustom);
          context.saveObject(custom);
          context.commitTransaction();
          //comment decache //context.decache(custom);
        }
      }
          
          //To add data of the identities from Custom - Based on mismatches from the Lifecycle state on email or operId
      
        List tobeRemovedList = new ArrayList();
          if(!Util.isEmpty(identitiesFromCustom) && Util.isNotNullOrEmpty(fullFeedFilePath)){
            Map fullDataMap =  readFullDataFile(fullFeedFilePath);
            
            if(!Util.isEmpty(fullDataMap) && !Util.isEmpty(identitiesFromCustom)){
               int countOfIdentites = 0;
			    Map allRecordsMap = fullDataMap.get("Full Data");
                for(String identityName : identitiesFromCustom){
					 boolean isProcessed = false;
                  boolean isEligibleToAddNow = isIdentityEligible(identityName);
                  
                  if(isEligibleToAddNow && !Util.isEmpty(allRecordsMap) && allRecordsMap.containsKey(identityName)){
                      Map addInputMap = allRecordsMap.get(identityName);
                      if(!Util.isEmpty(addInputMap) ){
						 if( addInputMap.containsKey("Oprid")) {
							addInputMap.remove("Oprid");
						 }
                        Map processedMap = processIdentities(addInputMap,customObjectName);
                        if(!Util.isEmpty(processedMap)){
                           updatedDataList.add(processedMap);
                         
							tobeRemovedList.add(identityName);
							isProcessed = true;
						}
                        countOfIdentites++;
                      }
                   }
				if( !isProcessed){
                       if(expectionIds != null && !Util.isEmpty(expectionIds)){
                        expectionIds.add(identityName);
                      }else{
                        expectionIds = new ArrayList();
                        expectionIds.add(identityName);
                      }
                  }                  
               }
            }
          }
   
            // Identity Names from Custom are eligible now - So remove them from the Custom 
            if(!Util.isEmpty(tobeRemovedList)){
               Custom custom = context.getObjectByName(Custom.class, customObjectName);
             	 if(custom != null){
             		 Object identityCustom = custom.get("Exception Identities");
                 if(identityCustom != null && identityCustom instanceof List){
                    identityCustom.removeAll(tobeRemovedList);
                    custom.put("Exception Identities", identityCustom);
                 }else{
                    custom.put("Exception Identities", new ArrayList());
                  }
                 context.saveObject(custom);
                 context.commitTransaction();
                 //comment decache //context.decache(custom);
              }
            }
         
           Custom custom = context.getObjectByName(Custom.class, customObjectName);
           if(custom != null && !Util.isEmpty(expectionIds) ){
              
              Object obj = custom.get("Exception Identities");
              if(obj != null && obj instanceof List){
                   obj.addAll(expectionIds);
                   custom.put("Exception Identities", obj);
               }else{
                  List idList = new ArrayList();
                  idList.addAll(expectionIds);
                  custom.put("Exception Identities", idList);
                }
                context.saveObject(custom);
                context.commitTransaction();
                //comment decache //context.decache(custom);
              }
    
         if(!Util.isEmpty(allUsersList)){
          //Iterate through all the lines in the input file and process them based on email and OprId availability
          for(Map inputMap : allUsersList){
              Map processedMap = processIdentities(inputMap, customObjectName);
               if(!Util.isEmpty(processedMap)){
                 updatedDataList.add(processedMap);
              }
           }
        }
    			 //If there is update data - Convert that to StringBuffer to add to the output file at the end
          if(!Util.isEmpty(updatedDataList) && Util.isNotNullOrEmpty(headerString)){
            data = convertData(updatedDataList, headerString);
          }
          
          //Remove duplicated from exceptions List from Custom Object - As data is bad.    
           removeDuplicatesFromExceptions(customObjectName);
      
          //Create file using this method
          if(data != null && Util.isNotNullOrEmpty(outputFilePath)){
              createOutputFile(data, outputFilePath);
          }
        
          Custom custom = context.getObjectByName(Custom.class, customObjectName);
          //Clear Custom for the identities mismatched from Event
          if(custom != null){
            List clearList = new ArrayList();
            custom.put("Identities Changed", clearList);
            context.saveObject(custom);
            context.commitTransaction();
            //comment decache //context.decache(custom);
          }
        }
  }
